from graphene import Object, String, List, Float
from flask import Flask
from flask_graphql import GraphQLView
from graphene_sqlalchemy import SQLAlchemyObjectType, SQLAlchemyConnectionField
from sqlalchemy import create_engine, Column, Integer, String, Float
from sqlalchemy.orm import relationship, sessionmaker

# Create Flask app
app = Flask(__name__)

# Create SQLAlchemy engine
engine = create_engine('sqlite:///catalog.db')

# Create SQLAlchemy session
Session = sessionmaker(bind=engine)
session = Session()

# Define SQLAlchemy models
class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Float)
    category_id = Column(Integer, ForeignKey('categories.id'))
    category = relationship('Category')

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship('Product')
    rating = Column(Integer)
    comment = Column(String)

# Define Graphene models
class CategoryType(SQLAlchemyObjectType):
    class Meta:
        model = Category

class ProductType(SQLAlchemyObjectType):
    class Meta:
        model = Product

class ReviewType(SQLAlchemyObjectType):
    class Meta:
        model = Review

# Define GraphQL schema
class Query(Object):
    products = SQLAlchemyConnectionField(ProductType)
    categories = SQLAlchemyConnectionField(CategoryType)
    reviews = SQLAlchemyConnectionField(ReviewType)

schema = graphene.Schema(query=Query)

# Add GraphQL view to Flask app
app.add_url_rule('/graphql', view_func=GraphQLView.as_view('graphql', schema=schema, graphiQL=True))

# Run Flask app
if __name__ == '__main__':
    app.run(debug=True)